16: class WasmAccessLog : public AccessLog::Instance {
17: public:
18:   WasmAccessLog(const PluginSharedPtr& plugin,
19:                 ThreadLocal::TypedSlotPtr<PluginHandleSharedPtrThreadLocal>&& tls_slot,
20:                 AccessLog::FilterPtr filter)
21:       : plugin_(plugin), tls_slot_(std::move(tls_slot)), filter_(std::move(filter)) {}
22: 
23:   void log(const Formatter::HttpFormatterContext& log_context,
24:            const StreamInfo::StreamInfo& stream_info) override {
25:     if (filter_) {
26:       if (!filter_->evaluate(log_context, stream_info)) {
27:         return;
28:       }
29:     }
30: 
31:     if (tls_slot_ != nullptr) {
32:       if (auto handle = tls_slot_->get()->handle(); handle != nullptr) {
33:         if (handle->wasmHandle()) {
34:           handle->wasmHandle()->wasm()->log(plugin_, log_context, stream_info);
35:         }
36:       }
37:     }
38:   }
39: 
40:   void setTlsSlot(ThreadLocal::TypedSlotPtr<PluginHandleSharedPtrThreadLocal>&& tls_slot) {
41:     ASSERT(tls_slot_ == nullptr);
42:     tls_slot_ = std::move(tls_slot);
43:   }
44: 
45: private:
46:   PluginSharedPtr plugin_;
47:   ThreadLocal::TypedSlotPtr<PluginHandleSharedPtrThreadLocal> tls_slot_;
48:   AccessLog::FilterPtr filter_;
49: };
